const input = $json;
const payload = typeof input.body === 'string' ? JSON.parse(input.body) : (input.body ?? input);

const socialMediaId = String(payload.socialMediaId ?? '').trim();
const userPrompt = String(payload.userPrompt ?? payload.prompt ?? '').trim();
const bearerToken = String(payload.bearerToken ?? payload.token ?? '').trim();
const topK = Math.min(Math.max(parseInt(payload.topK ?? 6, 10) || 6, 1), 20);
const maxReferenceImages = Math.min(Math.max(parseInt(payload.maxReferenceImages ?? 3, 10) || 3, 1), 4);

if (!socialMediaId) throw new Error('socialMediaId is required');
if (!userPrompt)    throw new Error('userPrompt is required');
if (!bearerToken)   throw new Error('bearerToken is required (user JWT for /api/Ai/recommendations)');

const gatewayBaseUrl = $env.AI_GATEWAY_BASE_URL || 'http://api-gateway:8080';
const openRouterBaseUrl = $env.OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1';
const openRouterKey = $env.OPENROUTER_API_KEY || '';
if (!openRouterKey) throw new Error('OPENROUTER_API_KEY env var not set on n8n container');

return [{ json: {
  socialMediaId,
  userPrompt,
  bearerToken,
  topK,
  maxReferenceImages,
  gatewayBaseUrl,
  openRouterBaseUrl,
  openRouterKey,
  recommendationsUrl: `${gatewayBaseUrl}/api/Ai/recommendations/${socialMediaId}/query`,
  openRouterChatUrl: `${openRouterBaseUrl}/chat/completions`
} }];

const input = $('Parse Input').first().json;
const rag = $json?.value ?? $json;
const answer = rag?.answer ?? '';
const references = Array.isArray(rag?.references) ? rag.references : [];

// Pick top-N references that have a direct image URL (text+visual fused refs come first by score).
const refsWithImages = references.filter(r => r && typeof r.imageUrl === 'string' && r.imageUrl.length > 0);
const topRefs = refsWithImages.slice(0, input.maxReferenceImages);

const captionsBlock = references
  .filter(r => r && r.caption)
  .slice(0, 6)
  .map((r, i) => `[${i + 1}] postId=${r.postId ?? 'n/a'} score=${(r.score ?? 0).toFixed(4)} caption="${String(r.caption).replace(/\s+/g, ' ').slice(0, 240)}"`)
  .join('\n');

const captionSystem = 'You are a social-media caption writer. You see (a) the user\'s topic for the next post, (b) recent post captions from the same account so you can match voice and style, and (c) a few reference images from past posts. Write ONE caption for the next post in the SAME language and tone as the past captions. Match emoji density and hashtag style. Output the caption only — no preface, no numbering, no markdown headings.';

const captionUserText = `User's topic for the next post: ${input.userPrompt}\n\nRetrieved RAG recommendation summary:\n${answer}\n\nRecent past captions from this account (for voice/style):\n${captionsBlock || '(none retrieved)'}\n\nIf reference images are attached, use them as visual context — describe scenes consistent with them when relevant.`;

const captionUserContent = [
  { type: 'text', text: captionUserText },
  ...topRefs.map(r => ({ type: 'image_url', image_url: { url: r.imageUrl } }))
];

const imageSystem = 'You are an image-generation assistant for social media. Produce ONE image that fits the user\'s topic AND matches the visual style of the reference images attached (color palette, lighting, composition, mood, subject framing). Output an image, not text.';

const imageUserText = `Generate an image for a social media post on this topic: ${input.userPrompt}.\n\nMatch the visual style of the attached reference images: same palette, same lighting, similar composition. Keep it brand-consistent.`;

const imageUserContent = [
  { type: 'text', text: imageUserText },
  ...topRefs.map(r => ({ type: 'image_url', image_url: { url: r.imageUrl } }))
];

return [{ json: {
  ...input,
  ragAnswer: answer,
  references,
  topRefs,
  captionPayload: {
    model: 'openai/gpt-4o-mini',
    temperature: 0.6,
    messages: [
      { role: 'system', content: captionSystem },
      { role: 'user', content: captionUserContent }
    ]
  },
  imagePayload: {
    model: 'openai/gpt-5.4-image-2',
    modalities: ['image', 'text'],
    messages: [
      { role: 'system', content: imageSystem },
      { role: 'user', content: imageUserContent }
    ]
  }
} }];

// Merge gives us [{caption response merged with image response}]. We pull both via
// $('Generate Caption (gpt-4o-mini)') and $('Generate Image (gpt-5.4-image-2)') for clarity.
const captionResp = $('Generate Caption (gpt-4o-mini)').first().json ?? {};
const imageResp = $('Generate Image (gpt-5.4-image-2)').first().json ?? {};
const prep = $('Prepare Prompts').first().json ?? {};

const caption = (captionResp.choices?.[0]?.message?.content ?? '').trim();

// gpt-5.4-image-2 returns the generated image either as data URL inside
// `choices[0].message.images[*].image_url.url` (newer OpenRouter shape) or
// embedded in `choices[0].message.content`. Try both.
const msg = imageResp.choices?.[0]?.message ?? {};
let generatedImageUrl = null;
if (Array.isArray(msg.images) && msg.images.length > 0) {
  const first = msg.images[0];
  generatedImageUrl = first?.image_url?.url ?? first?.url ?? null;
} else if (typeof msg.content === 'string' && msg.content.startsWith('data:image/')) {
  generatedImageUrl = msg.content;
}
const imageRawText = typeof msg.content === 'string' ? msg.content : null;

return [{ json: {
  socialMediaId: prep.socialMediaId,
  userPrompt: prep.userPrompt,
  ragAnswer: prep.ragAnswer,
  references: prep.references,
  topRefs: prep.topRefs,
  caption,
  captionUsage: captionResp.usage ?? null,
  generatedImageUrl,
  imageRawText,
  imageUsage: imageResp.usage ?? null,
  imageError: imageResp.error ?? null
} }];
